def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase.
    """
    if not triples:
        return ""

    # Group triples by subject to handle related entities (e.g., country info)
    subject_triples: dict[str, list[Triple]] = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Find the monument as the main subject (look for "Monument" in subject name)
    main_subject = None
    for subj in subject_triples.keys():
        if "Monument" in subj or "Memorial" in subj or "Plack" in subj:
            main_subject = subj
            break
    if main_subject is None:
        main_subject = triples[0].subject

    # Collect clauses for the main subject and related entities
    main_clauses: list[str] = []
    location_info: str = ""
    state_info: str = ""
    country_info: str = ""
    other_info: list[str] = []

    for subject, sub_triples in subject_triples.items():
        for triple in sub_triples:
            p = triple.predicate
            o = triple.object.strip('"')  # remove surrounding quotes if present

            # Map predicates to natural‑language fragments with better phrasing
            if subject == main_subject:
                if p == "category":
                    main_clauses.append(f"is a {o}")
                elif p in ("established", "foundingDate"):
                    main_clauses.append(f"was established on {o}")
                elif p == "inaugurationDate":
                    main_clauses.append(f"was inaugurated on {o}")
                elif p == "owner":
                    main_clauses.append(f"is owned by {o}")
                elif p == "owningOrganisation":
                    main_clauses.append(f"owned by {o}")
                elif p == "dedicatedTo":
                    main_clauses.append(f"is dedicated to {o}")
                elif p == "designer":
                    main_clauses.append(f"was designed by {o}")
                elif p == "material":
                    main_clauses.append(f"is made of {o}")
                elif p == "nativeName":
                    main_clauses.append(f'native name is "{o}"')
                elif p == "district":
                    main_clauses.append(f"in the district of {o}")
                elif p == "location":
                    location_info = o
                elif p == "municipality":
                    # Add to location chain instead
                    location_info = o if not location_info else f"{location_info}, {o}"
                elif p == "state":
                    state_info = o
                    # Don't add as main clause, handle in location phrase
                elif p == "country":
                    country_info = o.strip('"')
            else:
                # Handle related entity info (country, capital, etc.)
                if p == "capital":
                    country_info = f"{subject}, where the capital is {o}"
                elif p == "nearestCity":
                    other_info.append(f"nearest city is {o}")
                elif p == "leader":
                    other_info.append(f"leader is {o}")
                elif p == "leaderTitle":
                    other_info.append(f"leader title is {o}")
                elif p == "currency":
                    other_info.append(f"currency is {o}")
                elif p == "largestCity":
                    other_info.append(f"largest city is {o}")
                elif p == "ethnicGroup":
                    other_info.append(f"ethnic group includes {o}")
                elif p == "language":
                    other_info.append(f"language is {o}")
                elif p == "religion":
                    other_info.append(f"religion is {o}")
                elif p == "hasToItsNorth":
                    other_info.append(f"to its north is {o}")
                elif p == "hasToItsSouth":
                    other_info.append(f"to its south lies {o}")
                elif p == "hasToItsEast":
                    other_info.append(f"to its east is {o}")
                elif p == "hasToItsNortheast":
                    other_info.append(f"to its northeast is {o}")
                elif p == "hasToItsNorthwest":
                    other_info.append(f"to its northwest is {o}")
                elif p == "hasToItsWest":
                    other_info.append(f"to its west is {o}")
                elif p == "hasToItsEast":
                    other_info.append(f"to its east is {o}")
                elif p == "hasToItsNortheast":
                    other_info.append(f"to its northeast is {o}")
                elif p == "hasToItsNorthwest":
                    other_info.append(f"to its northwest is {o}")
                elif p == "hasToItsSoutheast":
                    other_info.append(f"to its southeast is {o}")
                elif p == "hasToItsSouthwest":
                    other_info.append(f"to its southwest is {o}")

    # Build the sentence with better structure
    sentence_parts: list[str] = []

    # Start with the main subject
    sentence_parts.append(main_subject)

    # Build location phrase
    location_phrase = []
    if location_info:
        location_phrase.append(location_info)
    if state_info:
        location_phrase.append(f"in {state_info}")
    if country_info:
        location_phrase.append(f"country {country_info}")

    if location_phrase:
        sentence_parts.append(f"is located in {', '.join(location_phrase)}")

    # Add main subject attributes
    if main_clauses:
        if len(main_clauses) == 1:
            sentence_parts.append(main_clauses[0])
        else:
            # Use semicolons for multiple clauses
            sentence_parts.append("; " + "; ".join(main_clauses))

    # Add related entity info
    if other_info:
        sentence_parts.append(f", with {', '.join(other_info)}")

    # Combine all parts into a single fluent sentence
    sentence = main_subject
    if location_phrase:
        sentence += f" is located in {', '.join(location_phrase)}"
    if main_clauses:
        sentence += ", " + ", ".join(main_clauses)
    if other_info:
        sentence += f", with {', '.join(other_info)}"
    sentence += "."

    return sentence

